export enum AppTab {
  TRANSLATE = 'TRANSLATE',
  FLASHCARDS = 'FLASHCARDS',
}

export interface Flashcard {
  id: string;
  original: string;
  translated: string;
  sourceLang?: string;
  targetLang: string;
  timestamp: number;
}

export interface TranslationResult {
  originalText: string;
  translatedText: string;
  detectedSourceLanguage?: string;
}

export enum TranslationMode {
  TEXT = 'TEXT',
  IMAGE = 'IMAGE',
  VOICE = 'VOICE',
}

import { GoogleGenAI, Type } from "@google/genai";
import { TranslationResult } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const translateText = async (
  text: string,
  targetLang: string
): Promise<TranslationResult> => {
  if (!apiKey) throw new Error("API Key not found");

  const prompt = `Translate the following text to ${targetLang}. 
  Identify the source language automatically.
  Return a JSON object with:
  - originalText: the input text
  - translatedText: the translation
  - detectedSourceLanguage: the name of the source language`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt + `\n\nText: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            originalText: { type: Type.STRING },
            translatedText: { type: Type.STRING },
            detectedSourceLanguage: { type: Type.STRING },
          },
          required: ["originalText", "translatedText"],
        },
      },
    });

    const result = JSON.parse(response.text || '{}');
    return {
      originalText: result.originalText || text,
      translatedText: result.translatedText || '',
      detectedSourceLanguage: result.detectedSourceLanguage,
    };
  } catch (error) {
    console.error("Text translation error:", error);
    throw new Error("Failed to translate text.");
  }
};

export const translateImage = async (
  file: File,
  targetLang: string
): Promise<TranslationResult> => {
  if (!apiKey) throw new Error("API Key not found");

  const base64Data = await fileToGenerativePart(file);

  // Note: gemini-2.5-flash-image does NOT support responseMimeType: "application/json"
  // We must use structured prompting and parsing.
  const prompt = `Identify the text in this image.
  1. Extract the text found in the image exactly.
  2. Translate that text to ${targetLang}.

  Format your response strictly as follows:
  ORIGINAL_START
  [Insert extracted text here]
  ORIGINAL_END
  TRANSLATION_START
  [Insert translated text here]
  TRANSLATION_END`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: file.type,
            },
          },
          { text: prompt },
        ],
      },
    });

    const text = response.text || '';

    // Parse the custom format
    const originalMatch = text.match(/ORIGINAL_START([\s\S]*?)ORIGINAL_END/);
    const translationMatch = text.match(/TRANSLATION_START([\s\S]*?)TRANSLATION_END/);

    const originalText = originalMatch ? originalMatch[1].trim() : "No text detected";
    const translatedText = translationMatch ? translationMatch[1].trim() : "Translation failed";

    return {
      originalText,
      translatedText,
      detectedSourceLanguage: 'Image Text',
    };

  } catch (error) {
    console.error("Image translation error:", error);
    throw new Error("Failed to translate image.");
  }
};

const fileToGenerativePart = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g. "data:image/jpeg;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

import { useState, useEffect, useCallback } from 'react';

export const useSpeechRecognition = () => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [recognition, setRecognition] = useState<SpeechRecognition | null>(null);

  useEffect(() => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognitionInstance = new SpeechRecognition();
      recognitionInstance.continuous = false;
      recognitionInstance.interimResults = true;
      recognitionInstance.lang = 'en-US'; // Default, can be dynamic if needed

      recognitionInstance.onstart = () => setIsListening(true);
      recognitionInstance.onend = () => setIsListening(false);
      recognitionInstance.onerror = (event) => {
        console.error("Speech error", event);
        setError(event.error);
        setIsListening(false);
      };

      recognitionInstance.onresult = (event) => {
        let finalTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          }
        }
        if (finalTranscript) {
            setTranscript(finalTranscript);
        }
      };

      setRecognition(recognitionInstance);
    } else {
      setError("Speech recognition not supported in this browser.");
    }
  }, []);

  const startListening = useCallback(() => {
    if (recognition && !isListening) {
      setTranscript('');
      setError(null);
      try {
        recognition.start();
      } catch (e) {
        console.error(e);
      }
    }
  }, [recognition, isListening]);

  const stopListening = useCallback(() => {
    if (recognition && isListening) {
      recognition.stop();
    }
  }, [recognition, isListening]);

  return { isListening, transcript, startListening, stopListening, error, setTranscript };
};

import React, { useState, useEffect, useRef } from 'react';
import { TranslationResult, Flashcard } from '../types';
import { SUPPORTED_LANGUAGES } from '../constants';
import { translateText, translateImage } from '../services/geminiService';
import { useSpeechRecognition } from '../hooks/useSpeechRecognition';
import { Loader2, Mic, Image as ImageIcon, Copy, ArrowRight, Save, RotateCcw, X, Languages } from 'lucide-react';

interface TranslationViewProps {
  onSaveFlashcard: (card: Omit<Flashcard, 'id' | 'timestamp'>) => void;
}

const TranslationView: React.FC<TranslationViewProps> = ({ onSaveFlashcard }) => {
  const [inputText, setInputText] = useState('');
  const [targetLang, setTargetLang] = useState(SUPPORTED_LANGUAGES[0]);
  const [result, setResult] = useState<TranslationResult | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);

  const { isListening, transcript, startListening, stopListening, error: speechError, setTranscript } = useSpeechRecognition();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync speech transcript to input
  useEffect(() => {
    if (transcript) {
      setInputText(transcript);
    }
  }, [transcript]);

  const handleTranslate = async () => {
    if ((!inputText && !selectedImage) || isLoading) return;

    setIsLoading(true);
    setResult(null);

    try {
      let translationResult: TranslationResult;

      if (selectedImage) {
        translationResult = await translateImage(selectedImage, targetLang);
      } else {
        translationResult = await translateText(inputText, targetLang);
      }

      setResult(translationResult);
    } catch (error) {
      console.error(error);
      alert("Translation failed. Please check your API key and connection.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedImage(file);

      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);

      // Clear text input when image is selected to avoid confusion
      setInputText('');
    }
  };

  const clearImage = () => {
    setSelectedImage(null);
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSaveToFlashcards = () => {
    if (result) {
      onSaveFlashcard({
        original: result.originalText,
        translated: result.translatedText,
        sourceLang: result.detectedSourceLanguage,
        targetLang: targetLang,
      });
      alert("Saved to Flashcards!");
    }
  };

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto p-4 md:p-6 gap-6">
      {/* Header / Controls */}
      <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-slate-800 p-4 rounded-xl border border-slate-700 shadow-sm">
        <div className="flex items-center gap-2">
            <div className="p-2 bg-indigo-500/20 rounded-lg">
                <Languages className="w-6 h-6 text-indigo-400" />
            </div>
            <span className="font-semibold text-slate-200">Target Language</span>
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <select
            value={targetLang}
            onChange={(e) => setTargetLang(e.target.value)}
            className="flex-1 md:w-64 bg-slate-900 border border-slate-700 text-slate-100 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
          >
            {SUPPORTED_LANGUAGES.map((lang) => (
              <option key={lang} value={lang}>
                {lang}
              </option>
            ))}
          </select>
          <button
            onClick={handleTranslate}
            disabled={isLoading || (!inputText && !selectedImage)}
            className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white px-6 py-2 rounded-lg font-medium transition-colors flex items-center gap-2"
          >
            {isLoading ? <Loader2 className="animate-spin w-5 h-5" /> : "Translate"}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 h-full">
        {/* Input Section */}
        <div className="flex flex-col gap-4">
          <div className="bg-slate-800 rounded-xl border border-slate-700 flex flex-col h-96 shadow-sm overflow-hidden relative">
            <div className="p-3 border-b border-slate-700 bg-slate-800/50 flex justify-between items-center">
              <span className="text-sm font-medium text-slate-400 uppercase tracking-wider">Source</span>
              <div className="flex gap-2">
                <button
                  onClick={selectedImage ? clearImage : () => { setInputText(''); setTranscript(''); }}
                  className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white transition-colors"
                  title="Clear"
                >
                  <RotateCcw className="w-4 h-4" />
                </button>
              </div>
            </div>

            <div className="flex-1 relative">
              {selectedImage ? (
                <div className="w-full h-full p-4 flex flex-col items-center justify-center bg-slate-900/50 relative">
                  <img src={imagePreview!} alt="Preview" className="max-h-full max-w-full object-contain rounded-lg shadow-lg" />
                  <button 
                    onClick={clearImage}
                    className="absolute top-2 right-2 bg-slate-900/80 p-2 rounded-full hover:bg-red-500/80 text-white transition-colors"
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
              ) : (
                <textarea
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="Type text, paste clipboard, or use voice..."
                  className="w-full h-full bg-transparent p-4 resize-none outline-none text-lg text-slate-100 placeholder:text-slate-600"
                />
              )}
            </div>

            {/* Input Actions Toolbar */}
            <div className="p-3 bg-slate-800/80 border-t border-slate-700 flex gap-2 items-center">
              <button
                onClick={isListening ? stopListening : startListening}
                className={`p-3 rounded-full transition-all ${
                  isListening 
                    ? 'bg-red-500 text-white animate-pulse ring-4 ring-red-500/20' 
                    : 'bg-slate-700 text-slate-300 hover:bg-slate-600'
                }`}
                title="Voice Input"
              >
                <Mic className="w-5 h-5" />
              </button>

              <button
                onClick={() => fileInputRef.current?.click()}
                className={`p-3 rounded-full transition-all ${
                    selectedImage
                    ? 'bg-indigo-500 text-white'
                    : 'bg-slate-700 text-slate-300 hover:bg-slate-600'
                }`}
                title="Upload Image"
              >
                <ImageIcon className="w-5 h-5" />
              </button>
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleImageSelect}
                accept="image/*"
                className="hidden"
              />

              <div className="flex-1" />
              {speechError && <span className="text-xs text-red-400">{speechError}</span>}
              <div className="text-xs text-slate-500 px-2">
                {inputText.length} chars
              </div>
            </div>
          </div>
        </div>

        {/* Output Section */}
        <div className="flex flex-col gap-4">
          <div className="bg-slate-800 rounded-xl border border-slate-700 flex flex-col h-96 shadow-sm overflow-hidden relative">
             <div className="p-3 border-b border-slate-700 bg-slate-800/50 flex justify-between items-center">
              <span className="text-sm font-medium text-slate-400 uppercase tracking-wider">Translation</span>
              {result && (
                <span className="text-xs bg-indigo-900/50 text-indigo-300 px-2 py-1 rounded border border-indigo-500/20">
                    {result.detectedSourceLanguage || 'Detected'} <ArrowRight className="w-3 h-3 inline mx-1" /> {targetLang}
                </span>
              )}
            </div>

            <div className="flex-1 p-4 overflow-y-auto bg-slate-900/30">
              {isLoading ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-500 gap-4">
                  <Loader2 className="w-8 h-8 animate-spin text-indigo-500" />
                  <p className="animate-pulse">Translating...</p>
                </div>
              ) : result ? (
                <div className="flex flex-col gap-6">
                  <div>
                     <p className="text-xl leading-relaxed text-slate-100 font-medium">{result.translatedText}</p>
                  </div>
                  {result.detectedSourceLanguage === 'Image Text' && (
                     <div className="mt-4 pt-4 border-t border-slate-700/50">
                        <p className="text-xs text-slate-500 mb-1 uppercase">Original Text Detected</p>
                        <p className="text-sm text-slate-400 italic bg-slate-900/50 p-3 rounded-lg border border-slate-700/50">
                            {result.originalText}
                        </p>
                     </div>
                  )}
                </div>
              ) : (
                <div className="h-full flex items-center justify-center text-slate-600 text-sm italic">
                  Translation will appear here
                </div>
              )}
            </div>

             <div className="p-3 bg-slate-800/80 border-t border-slate-700 flex gap-2 justify-end">
               {result && (
                 <>
                    <button
                        onClick={() => {
                            navigator.clipboard.writeText(result.translatedText);
                        }}
                        className="flex items-center gap-2 px-4 py-2 text-sm text-slate-300 hover:bg-slate-700 rounded-lg transition-colors"
                    >
                        <Copy className="w-4 h-4" /> Copy
                    </button>
                    <button
                        onClick={handleSaveToFlashcards}
                        className="flex items-center gap-2 px-4 py-2 text-sm bg-emerald-600/20 text-emerald-400 border border-emerald-600/30 hover:bg-emerald-600/30 rounded-lg transition-colors"
                    >
                        <Save className="w-4 h-4" /> Save Flashcard
                    </button>
                 </>
               )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TranslationView;

import React, { useState } from 'react';
import { Flashcard } from '../types';
import { Trash2, RotateCw, ChevronLeft, ChevronRight, GraduationCap } from 'lucide-react';

interface FlashcardsViewProps {
  flashcards: Flashcard[];
  onDeleteFlashcard: (id: string) => void;
}

const FlashcardsView: React.FC<FlashcardsViewProps> = ({ flashcards, onDeleteFlashcard }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  if (flashcards.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-slate-500 p-8">
        <div className="w-24 h-24 bg-slate-800 rounded-full flex items-center justify-center mb-6 shadow-inner">
            <GraduationCap className="w-12 h-12 text-slate-600" />
        </div>
        <h3 className="text-xl font-semibold text-slate-300 mb-2">No Flashcards Yet</h3>
        <p className="text-center max-w-md">Translate something and click "Save Flashcard" to build your deck.</p>
      </div>
    );
  }

  const currentCard = flashcards[currentIndex];

  const handleNext = () => {
    setIsFlipped(false);
    setCurrentIndex((prev) => (prev + 1) % flashcards.length);
  };

  const handlePrev = () => {
    setIsFlipped(false);
    setCurrentIndex((prev) => (prev - 1 + flashcards.length) % flashcards.length);
  };

  const handleDelete = () => {
    onDeleteFlashcard(currentCard.id);
    if (flashcards.length === 1) {
        // We just deleted the last one
    } else if (currentIndex >= flashcards.length - 1) {
      setCurrentIndex(0);
    }
    setIsFlipped(false);
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto p-6">

      <div className="w-full flex justify-between items-center mb-8 px-4">
        <div className="text-slate-400 text-sm font-medium">
            Card {currentIndex + 1} of {flashcards.length}
        </div>
        <button 
            onClick={handleDelete}
            className="text-red-400 hover:text-red-300 hover:bg-red-400/10 p-2 rounded-lg transition-colors flex items-center gap-2 text-sm"
        >
            <Trash2 className="w-4 h-4" /> Delete Card
        </button>
      </div>

      <div className="relative w-full max-w-2xl aspect-[3/2] perspective-1000 group">
        <div 
            className={`relative w-full h-full duration-500 preserve-3d cursor-pointer transition-transform ${isFlipped ? 'rotate-y-180' : ''}`}
            onClick={() => setIsFlipped(!isFlipped)}
        >
            {/* Front */}
            <div className="absolute w-full h-full backface-hidden bg-gradient-to-br from-slate-700 to-slate-800 rounded-2xl shadow-xl border border-slate-600 flex flex-col items-center justify-center p-8 text-center">
                <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest mb-4 bg-indigo-900/30 px-3 py-1 rounded-full border border-indigo-500/20">
                    Original
                </span>
                <p className="text-3xl md:text-4xl font-bold text-slate-100 leading-tight">
                    {currentCard.original}
                </p>
                <p className="mt-8 text-slate-500 text-sm">Click to flip</p>
            </div>

            {/* Back */}
            <div className="absolute w-full h-full backface-hidden rotate-y-180 bg-gradient-to-br from-indigo-900 to-slate-800 rounded-2xl shadow-xl border border-indigo-500/30 flex flex-col items-center justify-center p-8 text-center">
                 <span className="text-xs font-bold text-emerald-400 uppercase tracking-widest mb-4 bg-emerald-900/30 px-3 py-1 rounded-full border border-emerald-500/20">
                    {currentCard.targetLang}
                </span>
                <p className="text-3xl md:text-4xl font-bold text-white leading-tight">
                    {currentCard.translated}
                </p>
                 <p className="mt-8 text-indigo-300/50 text-sm">Click to flip back</p>
            </div>
        </div>
      </div>

      <div className="flex gap-6 mt-10 items-center">
        <button 
            onClick={handlePrev}
            className="p-4 rounded-full bg-slate-800 border border-slate-700 hover:bg-slate-700 hover:border-slate-600 text-slate-200 transition-all shadow-lg active:scale-95"
        >
            <ChevronLeft className="w-6 h-6" />
        </button>

        <button 
            onClick={() => setIsFlipped(!isFlipped)}
            className="flex items-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full font-semibold shadow-lg shadow-indigo-500/20 transition-all active:scale-95"
        >
            <RotateCw className="w-5 h-5" /> Flip Card
        </button>

        <button 
            onClick={handleNext}
            className="p-4 rounded-full bg-slate-800 border border-slate-700 hover:bg-slate-700 hover:border-slate-600 text-slate-200 transition-all shadow-lg active:scale-95"
        >
            <ChevronRight className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default FlashcardsView;

import React, { useState, useEffect } from 'react';
import { AppTab, Flashcard } from './types';
import { LOCAL_STORAGE_KEY } from './constants';
import TranslationView from './components/TranslationView';
import FlashcardsView from './components/FlashcardsView';
import { Sparkles, Library, Globe2, LayoutTemplate } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.TRANSLATE);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [isMiniMode, setIsMiniMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        setFlashcards(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load flashcards", e);
      }
    }
  }, []);

  const saveFlashcard = (cardData: Omit<Flashcard, 'id' | 'timestamp'>) => {
    const newCard: Flashcard = {
      ...cardData,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
    };
    const updated = [newCard, ...flashcards];
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  const deleteFlashcard = (id: string) => {
    const updated = flashcards.filter(c => c.id !== id);
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  // Mini mode style simulation
  const containerClass = isMiniMode 
    ? "fixed bottom-4 right-4 w-[400px] h-[600px] shadow-2xl rounded-2xl overflow-hidden z-50 border border-slate-700" 
    : "w-full min-h-screen flex flex-col";

  return (
    <div className={`bg-slate-950 text-slate-100 transition-all duration-300 ${isMiniMode ? 'bg-transparent' : ''}`}>
      <div className={`${containerClass} bg-slate-900 transition-all duration-300`}>

        {/* Navbar */}
        <header className="flex items-center justify-between px-6 py-4 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-10">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-lg shadow-lg shadow-indigo-500/20">
                <Sparkles className="w-5 h-5 text-white" />
            </div>
            {!isMiniMode && <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">LinguaGemini</h1>}
          </div>

          <div className="flex bg-slate-800/80 p-1 rounded-xl">
             <button
                onClick={() => setActiveTab(AppTab.TRANSLATE)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  activeTab === AppTab.TRANSLATE 
                    ? 'bg-slate-700 text-white shadow-sm' 
                    : 'text-slate-400 hover:text-slate-200'
                }`}
             >
                <Globe2 className="w-4 h-4" />
                {!isMiniMode && "Translate"}
             </button>
