import FlashcardsView from './components/FlashcardsView';
import { Sparkles, Library, Globe2, LayoutTemplate } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.TRANSLATE);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [isMiniMode, setIsMiniMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        setFlashcards(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load flashcards", e);
      }
    }
  }, []);

  const saveFlashcard = (cardData: Omit<Flashcard, 'id' | 'timestamp'>) => {
    const newCard: Flashcard = {
      ...cardData,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
    };
    const updated = [newCard, ...flashcards];
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  const deleteFlashcard = (id: string) => {
    const updated = flashcards.filter(c => c.id !== id);
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  // Mini mode style simulation
  const containerClass = isMiniMode 
    ? "fixed bottom-4 right-4 w-[400px] h-[600px] shadow-2xl rounded-2xl overflow-hidden z-50 border border-slate-700" 
    : "w-full min-h-screen flex flex-col";

  return (
    <div className={`min-h-screen bg-slate-950 text-slate-100 transition-all duration-300 ${isMiniMode ? 'bg-transparent' : ''}`}>
      <div className={`${containerClass} bg-slate-900 transition-all duration-300`}>

        {/* Navbar */}
        <header className="flex items-center justify-between px-6 py-4 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-10">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-lg shadow-lg shadow-indigo-500/20">
                <Sparkles className="w-5 h-5 text-white" />
            </div>
            {!isMiniMode && <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">LinguaGemini</h1>}
          </div>

          <div className="flex bg-slate-800/80 p-1 rounded-xl">
             <button
                onClick={() => setActiveTab(AppTab.TRANSLATE)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  activeTab === AppTab.TRANSLATE 
                    ? 'bg-slate-700 text-white shadow-sm' 
                    : 'text-slate-400 hover:text-slate-200'
                }`}
             >
                <Globe2 className="w-4 h-4" />
                {!isMiniMode && "Translate"}
             </button>
             <button
                onClick={() => setActiveTab(AppTab.FLASHCARDS)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  activeTab === AppTab.FLASHCARDS 
                    ? 'bg-slate-700 text-white shadow-sm' 
                    : 'text-slate-400 hover:text-slate-200'
                }`}
             >
                <Library className="w-4 h-4" />
                {!isMiniMode && "Flashcards"}
             </button>
          </div>

          <button 
            onClick={() => setIsMiniMode(!isMiniMode)}
            className={`p-2 rounded-lg transition-colors ${isMiniMode ? 'bg-indigo-600 text-white' : 'hover:bg-slate-800 text-slate-400'}`}
            title={isMiniMode ? "Expand" : "Mini Widget Mode"}
          >
            <LayoutTemplate className="w-5 h-5" />
          </button>
        </header>

        {/* Content */}
        <main className="flex-1 overflow-hidden">
          {activeTab === AppTab.TRANSLATE ? (
            <TranslationView onSaveFlashcard={saveFlashcard} />
          ) : (
            <FlashcardsView flashcards={flashcards} onDeleteFlashcard={deleteFlashcard} />
          )}
        </main>

      </div>

      {/* Background decoration (only visible in full mode) */}
      {!isMiniMode && (
          <div className="fixed inset-0 pointer-events-none z-[-1] overflow-hidden">
             <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-900/10 rounded-full blur-3xl opacity-50" />
             <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-900/10 rounded-full blur-3xl opacity-50" />
          </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import type { TranslationResult } from "../types";

export const translateText = async (
  text: string,
  targetLang: string
): Promise<TranslationResult> => {
  // Initialize here to prevent top-level crash if process is undefined during module load
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  if (!process.env.API_KEY) throw new Error("API Key not found");

  const prompt = `Translate the following text to ${targetLang}. 
  Identify the source language automatically.
  Return a JSON object with:
  - originalText: the input text
  - translatedText: the translation
  - detectedSourceLanguage: the name of the source language`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt + `\n\nText: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            originalText: { type: Type.STRING },
            translatedText: { type: Type.STRING },
            detectedSourceLanguage: { type: Type.STRING },
          },
          required: ["originalText", "translatedText"],
        },
      },
    });

    const result = JSON.parse(response.text || '{}');
    return {
      originalText: result.originalText || text,
      translatedText: result.translatedText || '',
      detectedSourceLanguage: result.detectedSourceLanguage,
    };
  } catch (error) {
    console.error("Text translation error:", error);
    throw new Error("Failed to translate text.");
  }
};

export const translateImage = async (
  file: File,
  targetLang: string
): Promise<TranslationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  if (!process.env.API_KEY) throw new Error("API Key not found");

  const base64Data = await fileToGenerativePart(file);

  // Note: gemini-2.5-flash-image does NOT support responseMimeType: "application/json"
  // We must use structured prompting and parsing.
  const prompt = `Identify the text in this image.
  1. Extract the text found in the image exactly.
  2. Translate that text to ${targetLang}.

  Format your response strictly as follows:
  ORIGINAL_START
  [Insert extracted text here]
  ORIGINAL_END
  TRANSLATION_START
  [Insert translated text here]
  TRANSLATION_END`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: file.type,
            },
          },
          { text: prompt },
        ],
      },
    });

    const text = response.text || '';

    // Parse the custom format
    const originalMatch = text.match(/ORIGINAL_START([\s\S]*?)ORIGINAL_END/);
    const translationMatch = text.match(/TRANSLATION_START([\s\S]*?)TRANSLATION_END/);

    const originalText = originalMatch ? originalMatch[1].trim() : "No text detected";
    const translatedText = translationMatch ? translationMatch[1].trim() : "Translation failed";

    return {
      originalText,
      translatedText,
      detectedSourceLanguage: 'Image Text',
    };

  } catch (error) {
    console.error("Image translation error:", error);
    throw new Error("Failed to translate image.");
  }
};

const fileToGenerativePart = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g. "data:image/jpeg;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

