    const newCard: Flashcard = {
      ...cardData,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
    };
    const updated = [newCard, ...flashcards];
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  const deleteFlashcard = (id: string) => {
    const updated = flashcards.filter(c => c.id !== id);
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  // Mini mode style simulation
  const containerClass = isMiniMode 
    ? "fixed bottom-4 right-4 w-[400px] h-[600px] shadow-2xl rounded-2xl overflow-hidden z-50 border border-slate-700" 
    : "w-full min-h-screen flex flex-col";

  return (
    <div className={`min-h-screen bg-slate-950 text-slate-100 transition-all duration-300 ${isMiniMode ? 'bg-transparent' : ''}`}>
      <div className={`${containerClass} bg-slate-900 transition-all duration-300`}>

        {/* Navbar */}
        <header className="flex flex-col border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-10">
          {!hasApiKey && (
            <div className="bg-red-500/10 border-b border-red-500/20 p-2 text-center text-xs md:text-sm text-red-400 flex items-center justify-center gap-2">
               <AlertTriangle className="w-4 h-4" />
               <span>API Key missing. Create a <b>.env</b> file with <b>API_KEY=your_key</b> and restart.</span>
            </div>
          )}
          <div className="flex items-center justify-between px-6 py-4">
            <div className="flex items-center gap-3">
                <div className="p-2 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-lg shadow-lg shadow-indigo-500/20">
                    <Sparkles className="w-5 h-5 text-white" />
                </div>
                {!isMiniMode && <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400">LinguaGemini</h1>}
            </div>

            <div className="flex bg-slate-800/80 p-1 rounded-xl">
                <button
                    onClick={() => setActiveTab(AppTab.TRANSLATE)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                    activeTab === AppTab.TRANSLATE 
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-slate-400 hover:text-slate-200'
                    }`}
                >
                    <Globe2 className="w-4 h-4" />
                    {!isMiniMode && "Translate"}
                </button>
                <button
                    onClick={() => setActiveTab(AppTab.FLASHCARDS)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                    activeTab === AppTab.FLASHCARDS 
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-slate-400 hover:text-slate-200'
                    }`}
                >
                    <Library className="w-4 h-4" />
                    {!isMiniMode && "Flashcards"}
                </button>
            </div>

            <button 
                onClick={() => setIsMiniMode(!isMiniMode)}
                className={`p-2 rounded-lg transition-colors ${isMiniMode ? 'bg-indigo-600 text-white' : 'hover:bg-slate-800 text-slate-400'}`}
                title={isMiniMode ? "Expand" : "Mini Widget Mode"}
            >
                <LayoutTemplate className="w-5 h-5" />
            </button>
          </div>
        </header>

        {/* Content */}
        <main className="flex-1 overflow-hidden">
          {activeTab === AppTab.TRANSLATE ? (
            <TranslationView onSaveFlashcard={saveFlashcard} />
          ) : (
            <FlashcardsView flashcards={flashcards} onDeleteFlashcard={deleteFlashcard} />
          )}
        </main>

      </div>

      {/* Background decoration (only visible in full mode) */}
      {!isMiniMode && (
          <div className="fixed inset-0 pointer-events-none z-[-1] overflow-hidden">
             <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-900/10 rounded-full blur-3xl opacity-50" />
