import { GoogleGenAI, Type } from "@google/genai";
import type { TranslationResult } from "../types";

// Helper to safely access API Key with multiple fallbacks
const getApiKey = () => {
  // 1. Try the global constant injected by vite.config.ts
  try {
     // @ts-ignore
     if (typeof __API_KEY__ !== 'undefined' && __API_KEY__) {
        // @ts-ignore
        return __API_KEY__;
     }
  } catch (e) {
    // Ignore reference errors
  }

  // 2. Try standard Vite env vars (import.meta.env)
  if (import.meta.env.VITE_API_KEY) return import.meta.env.VITE_API_KEY;
  if (import.meta.env.VITE_GEMINI_API_KEY) return import.meta.env.VITE_GEMINI_API_KEY;
  if (import.meta.env.GEMINI_API_KEY) return import.meta.env.GEMINI_API_KEY;
  if (import.meta.env.API_KEY) return import.meta.env.API_KEY;

  // 3. Last resort check for process.env (rarely works in browser but good for consistency)
  try {
     // @ts-ignore
     if (process.env.API_KEY) return process.env.API_KEY;
  } catch(e) {}

  return '';
};

// Helper to check if key is valid for UI states
export const validateApiKey = (): boolean => {
  const key = getApiKey();
  return !!key && key.length > 0 && key !== "undefined";
};

export const translateText = async (
  text: string,
  targetLang: string
): Promise<TranslationResult> => {
  const apiKey = getApiKey();

  if (!apiKey || apiKey === "undefined") {
    console.error("CRITICAL ERROR: API Key is missing.");
    throw new Error("API Key not found. Please check your .env file.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `Translate the following text to ${targetLang}. 
  Identify the source language automatically.
  Return a JSON object with:
  - originalText: the input text
  - translatedText: the translation
  - detectedSourceLanguage: the name of the source language`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt + `\n\nText: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            originalText: { type: Type.STRING },
            translatedText: { type: Type.STRING },
            detectedSourceLanguage: { type: Type.STRING },
          },
          required: ["originalText", "translatedText"],
        },
      },
    });

    const result = JSON.parse(response.text || '{}');
    return {
      originalText: result.originalText || text,
      translatedText: result.translatedText || '',
      detectedSourceLanguage: result.detectedSourceLanguage,
    };
  } catch (error) {
    console.error("Text translation error details:", error);
    throw error;
  }
};

export const translateImage = async (
  file: File,
  targetLang: string
): Promise<TranslationResult> => {
  const apiKey = getApiKey();

  if (!apiKey || apiKey === "undefined") {
    console.error("CRITICAL ERROR: API Key is missing.");
    throw new Error("API Key not found");
  }

  const ai = new GoogleGenAI({ apiKey });

  const base64Data = await fileToGenerativePart(file);

  // Use gemini-3-flash-preview for multimodal tasks (Image + Text -> Text)
  // It supports JSON schema, making parsing reliable.
  const prompt = `Identify the text in this image.
  1. Extract the text found in the image exactly.
  2. Translate that text to ${targetLang}.

  Return a JSON object with:
  - originalText: the extracted text
  - translatedText: the translation
  - detectedSourceLanguage: the detected language of the text
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: file.type,
            },
          },
          { text: prompt },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
             originalText: { type: Type.STRING },
             translatedText: { type: Type.STRING },
             detectedSourceLanguage: { type: Type.STRING },
          },
           required: ["originalText", "translatedText"],
        }
      }
    });

    const result = JSON.parse(response.text || '{}');

    return {
      originalText: result.originalText || "No text detected",
      translatedText: result.translatedText || "Translation failed",
      detectedSourceLanguage: result.detectedSourceLanguage || 'Image Text',
    };

  } catch (error) {
    console.error("Image translation error details:", error);
    throw error;
  }
};

const fileToGenerativePart = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g. "data:image/jpeg;base64,")
      const base64Data = base64String.split(',')[1];
      resolve(base64Data);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

