import React, { useState, useEffect } from 'react';
import { AppTab, type Flashcard } from './types';
import { LOCAL_STORAGE_KEY } from './constants';
import { validateApiKey } from './services/geminiService';
import TranslationView from './components/TranslationView';
import FlashcardsView from './components/FlashcardsView';
import ExtensionView from './components/ExtensionView';
import { Sparkles, Library, Globe2, AlertTriangle, Puzzle } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.TRANSLATE);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [hasApiKey, setHasApiKey] = useState(true);
  const [notification, setNotification] = useState<string | null>(null);

  useEffect(() => {
    // Check for API key on mount
    const isValid = validateApiKey();
    setHasApiKey(isValid);

    // Load saved cards
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        setFlashcards(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load flashcards", e);
      }
    }

    // Check for incoming flashcards from the Chrome Extension via URL params
    const params = new URLSearchParams(window.location.search);
    if (params.get('autoSave') === 'true') {
        const original = params.get('original');
        const translated = params.get('translated');
        const sourceLang = params.get('sourceLang') || 'Auto';
        const targetLang = params.get('targetLang') || 'English';

        if (original && translated) {
            handleExternalSave({
                original,
                translated,
                sourceLang,
                targetLang
            });
            // Clean the URL
            window.history.replaceState({}, document.title, window.location.pathname);
            setNotification("Flashcard saved from Extension!");
            setTimeout(() => setNotification(null), 3000);
            setActiveTab(AppTab.FLASHCARDS);
        }
    }
  }, []);

  const handleExternalSave = (cardData: Omit<Flashcard, 'id' | 'timestamp'>) => {
    // We need to read current state from localStorage to avoid stale closures in useEffect if called there directly,
    // but here we are calling it via helper.
    // However, the cleanest way inside useEffect is to read/write to LS immediately then update state.
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    let currentCards: Flashcard[] = saved ? JSON.parse(saved) : [];

    const newCard: Flashcard = {
        ...cardData,
        id: crypto.randomUUID(),
        timestamp: Date.now(),
    };

    const updated = [newCard, ...currentCards];
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  const saveFlashcard = (cardData: Omit<Flashcard, 'id' | 'timestamp'>) => {
    const newCard: Flashcard = {
      ...cardData,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
    };
    const updated = [newCard, ...flashcards];
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  const deleteFlashcard = (id: string) => {
    const updated = flashcards.filter(c => c.id !== id);
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans selection:bg-indigo-500/30">
      <div className="w-full min-h-screen flex flex-col bg-slate-900">

        {/* Navbar */}
        <header className="flex flex-col border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
          {!hasApiKey && (
            <div className="bg-red-500/10 border-b border-red-500/20 p-2 text-center text-xs md:text-sm text-red-400 flex items-center justify-center gap-2">
               <AlertTriangle className="w-4 h-4" />
               <span>API Key missing. Create a <b>.env</b> file with <code>API_KEY=AIza...</code> in the project root.</span>
            </div>
          )}
          {notification && (
            <div className="bg-emerald-500/10 border-b border-emerald-500/20 p-2 text-center text-sm text-emerald-400 animate-in fade-in slide-in-from-top-2">
                {notification}
            </div>
          )}
          <div className="flex items-center justify-between px-6 py-4">
            <div className="flex items-center gap-3">
                <div className="p-2 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-lg shadow-lg shadow-indigo-500/20">
                    <Sparkles className="w-5 h-5 text-white" />
                </div>
                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400 hidden sm:block">LinguaGemini</h1>
            </div>

            <div className="flex bg-slate-800/80 p-1 rounded-xl overflow-x-auto">
                <button
                    onClick={() => setActiveTab(AppTab.TRANSLATE)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                    activeTab === AppTab.TRANSLATE 
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-slate-400 hover:text-slate-200'
                    }`}
                >
                    <Globe2 className="w-4 h-4" />
                    Translate
                </button>
                <button
                    onClick={() => setActiveTab(AppTab.FLASHCARDS)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                    activeTab === AppTab.FLASHCARDS 
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-slate-400 hover:text-slate-200'
                    }`}
                >
                    <Library className="w-4 h-4" />
                    Flashcards
                    <span className="ml-1 bg-slate-900 text-slate-400 text-xs px-2 py-0.5 rounded-full border border-slate-700">
                        {flashcards.length}
                    </span>
                </button>
                {/* Special Extension Tab */}
                 <button
                    onClick={() => setActiveTab('EXTENSION' as AppTab)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                    activeTab === ('EXTENSION' as AppTab)
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-indigo-400 hover:text-indigo-300'
                    }`}
                >
                    <Puzzle className="w-4 h-4" />
                    Get Extension
                </button>
            </div>
          </div>
        </header>

        {/* Content */}
        <main className="flex-1 overflow-hidden relative">
          {activeTab === AppTab.TRANSLATE ? (
            <TranslationView onSaveFlashcard={saveFlashcard} />
          ) : activeTab === AppTab.FLASHCARDS ? (
            <FlashcardsView flashcards={flashcards} onDeleteFlashcard={deleteFlashcard} />
          ) : (
            <ExtensionView />
          )}
        </main>
      </div>

      {/* Background decoration */}
      <div className="fixed inset-0 pointer-events-none z-[-1] overflow-hidden">
            <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-900/10 rounded-full blur-3xl opacity-50" />
            <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-900/10 rounded-full blur-3xl opacity-50" />
      </div>
    </div>
  );
};

export default App;

{
  "manifest_version": 3,
  "name": "LinguaGemini Assistant",
  "version": "1.0",
  "description": "Translate web content and sync to your LinguaGemini flashcards.",
  "permissions": ["activeTab", "storage", "scripting"],
  "action": {
    "default_popup": "popup.html",
    "default_title": "Translate with LinguaGemini"
  },
  "icons": {
    "16": "icon16.png",
    "48": "icon48.png",
    "128": "icon128.png"
  }
}

body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  margin: 0;
  padding: 0;
  background-color: #0f172a; /* Slate 900 */
  color: #f8fafc;
  width: 320px;
}

.container {
  padding: 16px;
}

.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
  border-bottom: 1px solid #1e293b;
  padding-bottom: 12px;
}

h1 {
  font-size: 18px;
  margin: 0;
  background: linear-gradient(to right, #818cf8, #c084fc);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

#settings-toggle {
  cursor: pointer;
  opacity: 0.7;
}

#settings-toggle:hover {
  opacity: 1;
}

textarea {
  width: 100%;
  height: 80px;
  background-color: #1e293b;
  border: 1px solid #334155;
  color: white;
  padding: 8px;
  border-radius: 8px;
  resize: none;
  font-family: inherit;
  box-sizing: border-box;
}

textarea:focus {
  outline: none;
  border-color: #6366f1;
}

.controls {
  display: flex;
  gap: 8px;
  margin-top: 12px;
}

select {
  flex: 1;
  background-color: #1e293b;
  color: white;
  border: 1px solid #334155;
  padding: 8px;
  border-radius: 6px;
}

button {
  cursor: pointer;
  border: none;
  padding: 8px 16px;
  border-radius: 6px;
  font-weight: 600;
  font-size: 13px;
  transition: opacity 0.2s;
}

button:hover {
  opacity: 0.9;
}

.primary-btn {
  background-color: #6366f1; /* Indigo 500 */
  color: white;
}

.accent-btn {
  background-color: #10b981; /* Emerald 500 */
  color: white;
  width: 100%;
}

.secondary-btn {
  background-color: #334155;
  color: #cbd5e1;
}

.result-area {
  margin-top: 16px;
  background-color: #1e293b;
  border-radius: 8px;
  padding: 12px;
  border: 1px solid #334155;
}

.label {
  font-size: 10px;
  text-transform: uppercase;
  color: #64748b;
  margin-bottom: 4px;
  font-weight: bold;
}

#translated-text {
  margin: 0 0 12px 0;
  font-size: 15px;
  line-height: 1.4;
}

.actions {
  display: flex;
  gap: 8px;
}

.hidden {
  display: none !important;
}

/* Loading Spinner */
.loading {
  display: flex;
  justify-content: center;
  padding: 20px;
}

.spinner {
  width: 24px;
  height: 24px;
  border: 3px solid #334155;
  border-top-color: #6366f1;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.input-group input {
  width: 100%;
  padding: 8px;
  background: #1e293b;
  border: 1px solid #334155;
  color: white;
  border-radius: 6px;
  box-sizing: border-box;
  margin-bottom: 8px;
}

.instruction {
  font-size: 14px;
  color: #cbd5e1;
  margin-bottom: 12px;
}

.tiny-text {
  font-size: 11px;
  color: #64748b;
  margin-top: 8px;
}

