    // Try to get selected text from active tab
    chrome.tabs.query({active: true, currentWindow: true}, (tabs) => {
        if(tabs[0].id) {
            chrome.scripting.executeScript({
                target: {tabId: tabs[0].id},
                func: () => window.getSelection().toString()
            }, (results) => {
                if (results && results[0] && results[0].result) {
                    sourceText.value = results[0].result;
                }
            });
        }
    });

    // Event Listeners
    saveKeyBtn.addEventListener('click', () => {
      const key = apiKeyInput.value.trim();
      if (key) {
        chrome.storage.sync.set({ geminiApiKey: key }, () => {
          showMain();
        });
      }
    });

    settingsToggle.addEventListener('click', showSetup);

    translateBtn.addEventListener('click', async () => {
        const text = sourceText.value.trim();
        const lang = targetLang.value;

        if (!text) return;

        showLoading();

        try {
            const result = await translateWithGemini(text, lang);
            translatedText.textContent = result;
            resultArea.classList.remove('hidden');
        } catch (e) {
            translatedText.textContent = "Error: " + e.message;
            resultArea.classList.remove('hidden');
        } finally {
            hideLoading();
        }
    });

    saveDeckBtn.addEventListener('click', () => {
        const original = encodeURIComponent(sourceText.value);
        const translated = encodeURIComponent(translatedText.textContent);
        const target = encodeURIComponent(targetLang.value);

        // Use localhost:3000 to sync with the running web app
        const url = `http://localhost:3000/?autoSave=true&original=${original}&translated=${translated}&targetLang=${target}`;
        chrome.tabs.create({ url });
    });

    copyBtn.addEventListener('click', () => {
        navigator.clipboard.writeText(translatedText.textContent);
        copyBtn.textContent = "Copied!";
        setTimeout(() => copyBtn.textContent = "Copy", 1500);
    });

    // --- Helpers ---

    function showSetup() {
      setupView.classList.remove('hidden');
      mainView.classList.add('hidden');
    }

    function showMain() {
      setupView.classList.add('hidden');
      mainView.classList.remove('hidden');
    }

    function showLoading() {
        loading.classList.remove('hidden');
        resultArea.classList.add('hidden');
    }

    function hideLoading() {
        loading.classList.add('hidden');
    }

    async function translateWithGemini(text, targetLanguage) {
        const data = await chrome.storage.sync.get(['geminiApiKey']);
        const apiKey = data.geminiApiKey;

        if (!apiKey) throw new Error("API Key missing");

        const prompt = `Translate this text to ${targetLanguage}. Only return the translated text, nothing else.\n\nText: "${text}"`;

        const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`;

        const response = await fetch(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                contents: [{
                    parts: [{ text: prompt }]
                }]
            })
        });

        if (!response.ok) {
            const err = await response.json();
            throw new Error(err.error?.message || "API Error");
        }

        const json = await response.json();
        return json.candidates[0].content.parts[0].text.trim();
    }
  });

