// 1. Sync API Key from Web App to Extension
function syncApiKey() {
  const bridge = document.getElementById('lingua-gemini-bridge');
  if (bridge && bridge.dataset.apiKey) {
    const key = bridge.dataset.apiKey;
    chrome.storage.sync.get(['geminiApiKey'], (data) => {
        if (data.geminiApiKey !== key) {
            chrome.storage.sync.set({ geminiApiKey: key }, () => {
                console.log("API Key synced from Web App to Extension");
            });
        }
    });
  }
}

// Run sync immediately and observe for changes (in case App loads slowly)
syncApiKey();
const observer = new MutationObserver(syncApiKey);
observer.observe(document.body, { childList: true, subtree: true });

// 2. Listen for Save Commands from Extension Popup
chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  if (request.action === "SAVE_FLASHCARD") {
    try {
      // Logic to save to LocalStorage
      const STORAGE_KEY = 'lingua_gemini_flashcards';
      const raw = localStorage.getItem(STORAGE_KEY);
      const cards = raw ? JSON.parse(raw) : [];

      const newCard = {
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        original: decodeURIComponent(request.data.original),
        translated: decodeURIComponent(request.data.translated),
        sourceLang: 'Auto',
        targetLang: decodeURIComponent(request.data.targetLang)
      };

      const updated = [newCard, ...cards];
      localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));

      // Dispatch custom event so React component updates
      window.dispatchEvent(new Event('lingua-gemini-update'));

      sendResponse({ success: true });
    } catch (e) {
      console.error(e);
      sendResponse({ success: false, error: e.message });
    }
  }
  return true;
});

