    const copyBtn = document.getElementById('copy-btn');
    const statusMsg = document.getElementById('status-msg');

    // 1. Initial Checks
    const data = await chrome.storage.sync.get(['geminiApiKey']);
    if (data.geminiApiKey) {
      showMain();
    } else {
      showSetup();
    }

    // Try to get selected text from active tab
    // Note: Since this is a window, 'activeTab' refers to the window itself unless we query appropriately
    // We need to find the "Last Active" tab in the normal browser window, not this popup window.
    chrome.tabs.query({active: true, lastFocusedWindow: true}, (tabs) => {
        if(tabs[0] && tabs[0].id) {
            chrome.scripting.executeScript({
                target: {tabId: tabs[0].id},
                func: () => window.getSelection().toString()
            }, (results) => {
                if (results && results[0] && results[0].result) {
                    sourceText.value = results[0].result;
                }
            });
        }
    });

