        // Find the LinguaGemini App tab
        chrome.tabs.query({ url: "*://localhost/*" }, (tabs) => {
            const appTab = tabs.find(t => t.url.includes(":3000"));

            if (appTab && appTab.id) {
                // App is open, send message to content script
                chrome.tabs.sendMessage(appTab.id, {
                    action: "SAVE_FLASHCARD",
                    data: { original, translated, targetLang: target }
                }, (response) => {
                    if (chrome.runtime.lastError) {
                         showStatus("Failed to communicate with app.", true);
                    } else if (response && response.success) {
                        showStatus("Saved to Flashcards!", false);
                    } else {
                        showStatus("Error saving card.", true);
                    }
                });
            } else {
                // App is not open
                showStatus("Please open LinguaGemini (localhost:3000) to save.", true);

                // Optional: Ask to open it
                /*
                if(confirm("LinguaGemini needs to be open to save. Open now?")) {
                    chrome.tabs.create({ url: 'http://localhost:3000' });
                }
                */
            }
        });
    });

    copyBtn.addEventListener('click', () => {
