        copyBtn.textContent = "Copied!";
        setTimeout(() => copyBtn.textContent = "Copy", 1500);
    });

    // --- Helpers ---

    function showStatus(msg, isError) {
        statusMsg.textContent = msg;
        statusMsg.style.color = isError ? '#f87171' : '#34d399';
        statusMsg.classList.remove('hidden');
        setTimeout(() => statusMsg.classList.add('hidden'), 4000);
    }

    function showSetup() {
      setupView.classList.remove('hidden');
      mainView.classList.add('hidden');
    }

    function showMain() {
      setupView.classList.add('hidden');
      mainView.classList.remove('hidden');
    }

    function showLoading() {
        loading.classList.remove('hidden');
        resultArea.classList.add('hidden');
    }

    function hideLoading() {
        loading.classList.add('hidden');
    }

    async function translateWithGemini(text, targetLanguage) {
        const data = await chrome.storage.sync.get(['geminiApiKey']);
        const apiKey = data.geminiApiKey;

        if (!apiKey) throw new Error("API Key missing");

        const prompt = `Translate this text to ${targetLanguage}. Only return the translated text, nothing else.\n\nText: "${text}"`;

        const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`;

        const response = await fetch(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                contents: [{
                    parts: [{ text: prompt }]
                }]
            })
        });

        if (!response.ok) {
            const err = await response.json();
            throw new Error(err.error?.message || "API Error");
        }

        const json = await response.json();
        return json.candidates[0].content.parts[0].text.trim();
    }
  });

import React, { useState, useEffect } from 'react';
import { AppTab, type Flashcard } from './types';
import { LOCAL_STORAGE_KEY, SUPPORTED_LANGUAGES } from './constants';
import { validateApiKey } from './services/geminiService';
import TranslationView from './components/TranslationView';
import FlashcardsView from './components/FlashcardsView';
import ExtensionView from './components/ExtensionView';
import { Sparkles, Library, Globe2, AlertTriangle, Puzzle } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.TRANSLATE);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [hasApiKey, setHasApiKey] = useState(true);
  const [notification, setNotification] = useState<string | null>(null);
  const [targetLang, setTargetLang] = useState(SUPPORTED_LANGUAGES[0]);

  // @ts-ignore
  const envApiKey = process.env.API_KEY;

  useEffect(() => {
    // Check for API key on mount
    const isValid = validateApiKey();
    setHasApiKey(isValid);

    // Load saved cards
    loadCards();

    // 1. Listen for Save events from Extension
    const handleExternalUpdate = () => {
        loadCards();
        setNotification("Flashcards synced from Extension!");
        setTimeout(() => setNotification(null), 3000);
    };

    // 2. Listen for Language changes from Extension
    const handleConfigUpdate = (e: CustomEvent) => {
        if (e.detail?.targetLang) {
            setTargetLang(e.detail.targetLang);
        }
    };

    window.addEventListener('lingua-gemini-update', handleExternalUpdate);
    window.addEventListener('lingua-gemini-config-update', handleConfigUpdate as EventListener);

    return () => {
        window.removeEventListener('lingua-gemini-update', handleExternalUpdate);
        window.removeEventListener('lingua-gemini-config-update', handleConfigUpdate as EventListener);
    };
  }, []);

  const loadCards = () => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        setFlashcards(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load flashcards", e);
      }
    }
  };

  const saveFlashcard = (cardData: Omit<Flashcard, 'id' | 'timestamp'>) => {
    const newCard: Flashcard = {
      ...cardData,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
    };
    const updated = [newCard, ...flashcards];
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  const deleteFlashcard = (id: string) => {
    const updated = flashcards.filter(c => c.id !== id);
    setFlashcards(updated);
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 font-sans selection:bg-indigo-500/30">

      {/* Hidden Bridge for Extension to Scrape/Inject Data */}
      {hasApiKey && (
          <div 
            id="lingua-gemini-bridge" 
            data-api-key={envApiKey}
            data-target-lang={targetLang}
            style={{ display: 'none' }} 
            aria-hidden="true" 
          />
      )}

      <div className="w-full min-h-screen flex flex-col bg-slate-900">

        {/* Navbar */}
        <header className="flex flex-col border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
          {!hasApiKey && (
            <div className="bg-red-500/10 border-b border-red-500/20 p-2 text-center text-xs md:text-sm text-red-400 flex items-center justify-center gap-2">
               <AlertTriangle className="w-4 h-4" />
               <span>API Key missing. Create a <b>.env</b> file with <code>API_KEY=AIza...</code> in the project root.</span>
            </div>
          )}
          {notification && (
            <div className="bg-emerald-500/10 border-b border-emerald-500/20 p-2 text-center text-sm text-emerald-400 animate-in fade-in slide-in-from-top-2">
                {notification}
            </div>
          )}
          <div className="flex items-center justify-between px-6 py-4">
            <div className="flex items-center gap-3">
                <div className="p-2 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-lg shadow-lg shadow-indigo-500/20">
                    <Sparkles className="w-5 h-5 text-white" />
                </div>
                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 to-purple-400 hidden sm:block">LinguaGemini</h1>
            </div>

            <div className="flex bg-slate-800/80 p-1 rounded-xl overflow-x-auto">
                <button
                    onClick={() => setActiveTab(AppTab.TRANSLATE)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                    activeTab === AppTab.TRANSLATE 
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-slate-400 hover:text-slate-200'
                    }`}
                >
                    <Globe2 className="w-4 h-4" />
                    Translate
                </button>
                <button
                    onClick={() => setActiveTab(AppTab.FLASHCARDS)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                    activeTab === AppTab.FLASHCARDS 
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-slate-400 hover:text-slate-200'
                    }`}
                >
                    <Library className="w-4 h-4" />
                    Flashcards
                    <span className="ml-1 bg-slate-900 text-slate-400 text-xs px-2 py-0.5 rounded-full border border-slate-700">
                        {flashcards.length}
                    </span>
                </button>
                 <button
                    onClick={() => setActiveTab('EXTENSION' as AppTab)}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                    activeTab === ('EXTENSION' as AppTab)
                        ? 'bg-slate-700 text-white shadow-sm' 
                        : 'text-indigo-400 hover:text-indigo-300'
                    }`}
                >
                    <Puzzle className="w-4 h-4" />
                    Get Extension
                </button>
            </div>
          </div>
        </header>

        {/* Content */}
        <main className="flex-1 overflow-hidden relative">
          {activeTab === AppTab.TRANSLATE ? (
            <TranslationView 
                onSaveFlashcard={saveFlashcard} 
                targetLang={targetLang}
                setTargetLang={setTargetLang}
            />
          ) : activeTab === AppTab.FLASHCARDS ? (
            <FlashcardsView flashcards={flashcards} onDeleteFlashcard={deleteFlashcard} />
          ) : (
            <ExtensionView />
          )}
        </main>
      </div>

      {/* Background decoration */}
      <div className="fixed inset-0 pointer-events-none z-[-1] overflow-hidden">
            <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-900/10 rounded-full blur-3xl opacity-50" />
            <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-900/10 rounded-full blur-3xl opacity-50" />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import type { TranslationResult, Flashcard } from '../types';
import { SUPPORTED_LANGUAGES } from '../constants';
import { translateText, translateImage } from '../services/geminiService';
import { useSpeechRecognition } from '../hooks/useSpeechRecognition';
import { Loader2, Mic, Image as ImageIcon, Copy, ArrowRight, Save, RotateCcw, X, Languages } from 'lucide-react';

interface TranslationViewProps {
  onSaveFlashcard: (card: Omit<Flashcard, 'id' | 'timestamp'>) => void;
  targetLang: string;
  setTargetLang: (lang: string) => void;
}

const TranslationView: React.FC<TranslationViewProps> = ({ onSaveFlashcard, targetLang, setTargetLang }) => {
  const [inputText, setInputText] = useState('');
  const [result, setResult] = useState<TranslationResult | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);

  const { isListening, transcript, startListening, stopListening, error: speechError, setTranscript } = useSpeechRecognition();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync speech transcript to input
  useEffect(() => {
    if (transcript) {
      setInputText(transcript);
    }
  }, [transcript]);

  const handleTranslate = async () => {
    if ((!inputText && !selectedImage) || isLoading) return;

    setIsLoading(true);
    setResult(null);

    try {
      let translationResult: TranslationResult;

      if (selectedImage) {
        translationResult = await translateImage(selectedImage, targetLang);
      } else {
        translationResult = await translateText(inputText, targetLang);
      }

      setResult(translationResult);
    } catch (error) {
      console.error(error);
      alert("Translation failed. Please check your API key and connection.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedImage(file);

      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);

      // Clear text input when image is selected to avoid confusion
      setInputText('');
    }
  };

  const clearImage = () => {
    setSelectedImage(null);
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSaveToFlashcards = () => {
    if (result) {
      onSaveFlashcard({
        original: result.originalText,
        translated: result.translatedText,
        sourceLang: result.detectedSourceLanguage,
        targetLang: targetLang,
      });
      alert("Saved to Flashcards!");
    }
  };

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto p-4 md:p-6 gap-6">
      {/* Header / Controls */}
      <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-slate-800 p-4 rounded-xl border border-slate-700 shadow-sm">
        <div className="flex items-center gap-2">
            <div className="p-2 bg-indigo-500/20 rounded-lg">
                <Languages className="w-6 h-6 text-indigo-400" />
            </div>
            <span className="font-semibold text-slate-200">Target Language</span>
        </div>
        <div className="flex gap-2 w-full md:w-auto">
          <select
            value={targetLang}
            onChange={(e) => setTargetLang(e.target.value)}
            className="flex-1 md:w-64 bg-slate-900 border border-slate-700 text-slate-100 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
          >
            {SUPPORTED_LANGUAGES.map((lang) => (
              <option key={lang} value={lang}>
                {lang}
              </option>
            ))}
          </select>
          <button
            onClick={handleTranslate}
            disabled={isLoading || (!inputText && !selectedImage)}
            className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white px-6 py-2 rounded-lg font-medium transition-colors flex items-center gap-2"
          >
            {isLoading ? <Loader2 className="animate-spin w-5 h-5" /> : "Translate"}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 h-full">
        {/* Input Section */}
        <div className="flex flex-col gap-4">
          <div className="bg-slate-800 rounded-xl border border-slate-700 flex flex-col h-96 shadow-sm overflow-hidden relative">
            <div className="p-3 border-b border-slate-700 bg-slate-800/50 flex justify-between items-center">
              <span className="text-sm font-medium text-slate-400 uppercase tracking-wider">Source</span>
              <div className="flex gap-2">
                <button
                  onClick={selectedImage ? clearImage : () => { setInputText(''); setTranscript(''); }}
                  className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white transition-colors"
                  title="Clear"
                >
                  <RotateCcw className="w-4 h-4" />
                </button>
              </div>
            </div>

            <div className="flex-1 relative">
              {selectedImage ? (
                <div className="w-full h-full p-4 flex flex-col items-center justify-center bg-slate-900/50 relative">
                  <img src={imagePreview!} alt="Preview" className="max-h-full max-w-full object-contain rounded-lg shadow-lg" />
                  <button 
                    onClick={clearImage}
                    className="absolute top-2 right-2 bg-slate-900/80 p-2 rounded-full hover:bg-red-500/80 text-white transition-colors"
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
              ) : (
                <textarea
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="Type text, paste clipboard, or use voice..."
                  className="w-full h-full bg-transparent p-4 resize-none outline-none text-lg text-slate-100 placeholder:text-slate-600"
                />
              )}
            </div>

            {/* Input Actions Toolbar */}
            <div className="p-3 bg-slate-800/80 border-t border-slate-700 flex gap-2 items-center">
              <button
                onClick={isListening ? stopListening : startListening}
                className={`p-3 rounded-full transition-all ${
                  isListening 
                    ? 'bg-red-500 text-white animate-pulse ring-4 ring-red-500/20' 
                    : 'bg-slate-700 text-slate-300 hover:bg-slate-600'
                }`}
                title="Voice Input"
              >
                <Mic className="w-5 h-5" />
              </button>

              <button
                onClick={() => fileInputRef.current?.click()}
                className={`p-3 rounded-full transition-all ${
                    selectedImage
                    ? 'bg-indigo-500 text-white'
                    : 'bg-slate-700 text-slate-300 hover:bg-slate-600'
                }`}
                title="Upload Image"
              >
                <ImageIcon className="w-5 h-5" />
              </button>
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleImageSelect}
                accept="image/*"
                className="hidden"
              />

              <div className="flex-1" />
              {speechError && <span className="text-xs text-red-400">{speechError}</span>}
              <div className="text-xs text-slate-500 px-2">
                {inputText.length} chars
              </div>
            </div>
          </div>
        </div>

        {/* Output Section */}
        <div className="flex flex-col gap-4">
          <div className="bg-slate-800 rounded-xl border border-slate-700 flex flex-col h-96 shadow-sm overflow-hidden relative">
             <div className="p-3 border-b border-slate-700 bg-slate-800/50 flex justify-between items-center">
              <span className="text-sm font-medium text-slate-400 uppercase tracking-wider">Translation</span>
              {result && (
                <span className="text-xs bg-indigo-900/50 text-indigo-300 px-2 py-1 rounded border border-indigo-500/20">
                    {result.detectedSourceLanguage || 'Detected'} <ArrowRight className="w-3 h-3 inline mx-1" /> {targetLang}
                </span>
              )}
            </div>

            <div className="flex-1 p-4 overflow-y-auto bg-slate-900/30">
              {isLoading ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-500 gap-4">
                  <Loader2 className="w-8 h-8 animate-spin text-indigo-500" />
                  <p className="animate-pulse">Translating...</p>
                </div>
              ) : result ? (
                <div className="flex flex-col gap-6">
                  <div>
                     <p className="text-xl leading-relaxed text-slate-100 font-medium">{result.translatedText}</p>
                  </div>
                  {result.detectedSourceLanguage === 'Image Text' && (
                     <div className="mt-4 pt-4 border-t border-slate-700/50">
                        <p className="text-xs text-slate-500 mb-1 uppercase">Original Text Detected</p>
                        <p className="text-sm text-slate-400 italic bg-slate-900/50 p-3 rounded-lg border border-slate-700/50">
                            {result.originalText}
                        </p>
                     </div>
                  )}
                </div>
              ) : (
                <div className="h-full flex items-center justify-center text-slate-600 text-sm italic">
                  Translation will appear here
                </div>
              )}
            </div>

             <div className="p-3 bg-slate-800/80 border-t border-slate-700 flex gap-2 justify-end">
               {result && (
                 <>
                    <button
                        onClick={() => {
                            navigator.clipboard.writeText(result.translatedText);
                        }}
                        className="flex items-center gap-2 px-4 py-2 text-sm text-slate-300 hover:bg-slate-700 rounded-lg transition-colors"
                    >
                        <Copy className="w-4 h-4" /> Copy
                    </button>
                    <button
                        onClick={handleSaveToFlashcards}
                        className="flex items-center gap-2 px-4 py-2 text-sm bg-emerald-600/20 text-emerald-400 border border-emerald-600/30 hover:bg-emerald-600/30 rounded-lg transition-colors"
                    >
                        <Save className="w-4 h-4" /> Save Flashcard
                    </button>
                 </>
               )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TranslationView;

{
  "manifest_version": 3,
  "name": "LinguaGemini Assistant",
  "version": "2.0",
  "description": "Auto-translate selected text and sync to flashcards.",
  "permissions": ["storage", "scripting"],
  "host_permissions": ["http://*/*", "https://*/*"],
  "background": {
    "service_worker": "background.js"
  },
  "content_scripts": [
    {
      "matches": ["http://localhost:3000/*", "http://127.0.0.1:3000/*"],
      "js": ["content.js"]
    },
    {
      "matches": ["http://*/*", "https://*/*"],
      "js": ["text_selection.js"],
      "css": ["selection.css"]
    }
  ],
  "action": {
    "default_popup": "popup.html",
    "default_title": "LinguaGemini Settings"
  },
  "commands": {
    "toggle_mode": {
      "suggested_key": {
        "default": "Ctrl+Q",
        "mac": "Command+Q"
      },
      "description": "Toggle Instant Translation Mode"
    }
  }
}

// background.js

// Initialize default state
chrome.runtime.onInstalled.addListener(() => {
  chrome.storage.local.set({ isActive: false });
  updateBadge(false);
});

// Toggle mode via Shortcut
chrome.commands.onCommand.addListener((command) => {
  if (command === "toggle_mode") {
    toggleActiveState();
  }
});

function toggleActiveState() {
  chrome.storage.local.get(['isActive'], (result) => {
    const newState = !result.isActive;
    chrome.storage.local.set({ isActive: newState });
    updateBadge(newState);
  });
}

function updateBadge(isActive) {
  const text = isActive ? "ON" : "OFF";
  const color = isActive ? "#10b981" : "#64748b";
  chrome.action.setBadgeText({ text: text });
  chrome.action.setBadgeBackgroundColor({ color: color });
}

// Handle Messages
chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  if (request.action === "TRANSLATE") {
    translateText(request.text, request.targetLang)
      .then(result => sendResponse({ success: true, result }))
      .catch(err => sendResponse({ success: false, error: err.message }));
    return true; // Async response
  }

  if (request.action === "QUEUE_SAVE") {
    queueFlashcard(request.data);
    sendResponse({ success: true });
  }

  if (request.action === "TOGGLE_STATE") {
      toggleActiveState();
      sendResponse({success: true});
  }
});

// Helper: Add to Sync Queue (for retrieval by Localhost content script)
function queueFlashcard(data) {
  chrome.storage.local.get(['saveQueue'], (res) => {
    const queue = res.saveQueue || [];
    queue.push(data);
    chrome.storage.local.set({ saveQueue: queue });
  });
}

// Helper: Call Gemini
async function translateText(text, targetLanguage) {
  const data = await chrome.storage.sync.get(['geminiApiKey']);
  const apiKey = data.geminiApiKey;

  if (!apiKey) throw new Error("API Key missing. Please open LinguaGemini.");

  const prompt = `Translate this text to ${targetLanguage}. Only return the translated text, nothing else.\n\nText: "${text}"`;

  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`;

  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{ parts: [{ text: prompt }] }]
    })
  });

  if (!response.ok) {
    const err = await response.json();
    throw new Error(err.error?.message || "API Error");
  }

  const json = await response.json();
  return json.candidates[0].content.parts[0].text.trim();
}

// content.js - Runs on Localhost (The Web App)

console.log("LinguaGemini Bridge Active");

const BRIDGE_ID = 'lingua-gemini-bridge';

// 1. Sync Config (App -> Extension)
function syncToExtension() {
  const bridge = document.getElementById(BRIDGE_ID);
  if (bridge) {
    // Sync API Key
    if (bridge.dataset.apiKey) {
       chrome.storage.sync.set({ geminiApiKey: bridge.dataset.apiKey });
    }
    // Sync Target Language
    if (bridge.dataset.targetLang) {
        chrome.storage.sync.set({ targetLang: bridge.dataset.targetLang });
    }
  }
}

// Observer to catch App state changes
const observer = new MutationObserver(syncToExtension);
observer.observe(document.body, { childList: true, subtree: true, attributes: true });
syncToExtension();

// 2. Sync Config (Extension -> App)
chrome.storage.onChanged.addListener((changes, area) => {
    if (area === 'sync' && changes.targetLang) {
        // Dispatch event to React App
        const event = new CustomEvent('lingua-gemini-config-update', { 
            detail: { targetLang: changes.targetLang.newValue } 
        });
        window.dispatchEvent(event);
    }
});

// 3. Process Save Queue (Extension -> App LocalStorage)
function processQueue() {
  chrome.storage.local.get(['saveQueue'], (res) => {
    const queue = res.saveQueue || [];
    if (queue.length > 0) {
      console.log(`Processing ${queue.length} saved flashcards...`);

      const STORAGE_KEY = 'lingua_gemini_flashcards';
      const raw = localStorage.getItem(STORAGE_KEY);
      let cards = raw ? JSON.parse(raw) : [];

      queue.forEach(item => {
        const newCard = {
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          original: item.original,
          translated: item.translated,
          sourceLang: 'Auto',
          targetLang: item.targetLang
        };
        cards.unshift(newCard); // Add to top
      });

      localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));

      // Clear queue
      chrome.storage.local.set({ saveQueue: [] });

      // Notify App to reload
      window.dispatchEvent(new Event('lingua-gemini-update'));
    }
  });
}

// Check queue on load and when window gains focus
processQueue();
window.addEventListener('focus', processQueue);
setInterval(processQueue, 2000); // Periodic check

// text_selection.js - Runs on all pages

let debounceTimer = null;
let currentBubble = null;

document.addEventListener('mouseup', (e) => {
  // Clear existing bubble if clicking outside
  if (currentBubble && !currentBubble.contains(e.target)) {
    removeBubble();
  }

  clearTimeout(debounceTimer);
  debounceTimer = setTimeout(async () => {
    const selection = window.getSelection();
    const text = selection.toString().trim();

    if (text.length > 0) {
      // Check if extension is active
      const state = await chrome.storage.local.get(['isActive']);
      if (state.isActive) {
         handleSelection(selection, text);
      }
    }
  }, 500); // 500ms delay to ensure selection is intentional
});

async function handleSelection(selection, text) {
  // Get Target Lang
  const conf = await chrome.storage.sync.get(['targetLang']);
  const targetLang = conf.targetLang || 'English';

  // Calculate position
  const range = selection.getRangeAt(0);
  const rect = range.getBoundingClientRect();

  // Show Loading Bubble
  showBubble(rect, "Translating...", true);

  // Request Translation
  chrome.runtime.sendMessage({ 
    action: 'TRANSLATE', 
    text: text, 
    targetLang: targetLang 
  }, (response) => {
    if (response && response.success) {
      updateBubble(response.result, text, targetLang);
    } else {
      updateBubble("Error: " + (response?.error || "Unknown"), null, null, true);
    }
  });
}

function showBubble(rect, content, isLoading = false) {
  removeBubble();

  const bubble = document.createElement('div');
  bubble.id = 'lingua-gemini-bubble';
  bubble.className = 'lg-bubble-container';

  // Position it below the selection
  const top = rect.bottom + window.scrollY + 10;
  const left = rect.left + window.scrollX;

  bubble.style.top = `${top}px`;
  bubble.style.left = `${left}px`;

  if (isLoading) {
    bubble.innerHTML = `<div class="lg-spinner"></div>`;
