    if (bridge.dataset.apiKey) {
       chrome.storage.sync.set({ geminiApiKey: bridge.dataset.apiKey }, () => {
           console.log("%cLinguaGemini: API Key Synced from Web App", "color: #10b981; font-weight: bold;");
