                        {flashcards.length}
                    </span>
                </button>
            </div>
          </div>
        </header>

        {/* Content */}
        <main className="flex-1 overflow-hidden relative">
          {activeTab === AppTab.TRANSLATE ? (
            <TranslationView 
                onSaveFlashcard={saveFlashcard} 
                targetLang={targetLang}
                setTargetLang={setTargetLang}
